#==============================================================================
#
# bag.map
# doel: serveren van BAG
#
#==============================================================================

MAP
  NAME "bagmap"  # Should differ from the group name!
  INCLUDE "header.inc"


  WEB
    METADATA
      "team" "BENK"
      "ows_title"    "BAG"
      "ows_abstract" "BAG objecten met een geografische component, waarvan Amsterdam de bronhouder is"

      # Avoid top-level layer querying, exposes sublayers in QGis:
      "wms_rootlayer_name" ""
    END
  END



  # #=============================================================================
  # # LAYERS
  # #=============================================================================

  LAYER
    NAME            "openbareruimte"
    GROUP           "bag"
    INCLUDE         "connection/dataservices.inc"
    DATA "geometrie FROM (
        SELECT * FROM public.bag_openbareruimtes_v1
        WHERE coalesce(eind_geldigheid, now()) >= now()
    ) AS subquery USING srid=28992 USING UNIQUE id"
    TYPE            POLYGON
    MINSCALEDENOM   100
    MAXSCALEDENOM   40001
    TEMPLATE        "fooOnlyForWMSGetFeatureInfo.html"
    PROJECTION
    "init=epsg:28992"
    END

    METADATA
      "ows_title"           "Openbareruimte"
      "ows_group_title"     "BAG"
      "ows_abstract"        "BAG openbare ruimtes van de gemeente Amsterdam"
      "gml_featureid"       "ID"
      "gml_include_items"   "all"
      "ows_geomtype"        "Geometry"
    END

    CLASS
      NAME       "Weg"
      EXPRESSION ([type_code] = 1)
      STYLE
        ANTIALIAS      true
        COLOR          200 200 200
        OUTLINECOLOR   172 172 172
        WIDTH          1
        OPACITY         50    
      END
    END

    CLASS
      NAME       "Water"
      EXPRESSION ([type_code] = 2)
      STYLE
        ANTIALIAS      true
        COLOR          100 200 255
        OUTLINECOLOR   172 172 172
        WIDTH          1
        OPACITY         50
      END
    END

    CLASS
      NAME       "Spoorbaan"
      EXPRESSION ([type_code] = 3)
      STYLE
        ANTIALIAS      true
        COLOR          150 150 150
        OUTLINECOLOR   172 172 172
        WIDTH          1
        OPACITY         50
      END
    END

    CLASS
      NAME       "Terrein"
      EXPRESSION ([type_code] = 4)
      STYLE
        ANTIALIAS      true
        COLOR          100 255 100
        OUTLINECOLOR   172 172 172
        WIDTH          1
        OPACITY         50
      END
    END

    CLASS
      NAME       "Kunstwerk"
      EXPRESSION ([type_code] = 5)
      STYLE
        ANTIALIAS      true
        COLOR          255 175 100
        OUTLINECOLOR   172 172 172
        WIDTH          1
        OPACITY         50
      END
    END

    CLASS
      NAME       "Landschappelijk gebied"
      EXPRESSION ([type_code] = 6)
      STYLE
        ANTIALIAS      true
        COLOR          200 100 255
        OUTLINECOLOR   172 172 172
        WIDTH          1
        OPACITY         50
      END
    END

    CLASS
      NAME       "Administratief gebied"
      EXPRESSION ([type_code] = 7)
      STYLE
        ANTIALIAS      true
        COLOR          255 255 100
        OUTLINECOLOR   172 172 172
        WIDTH          1
        OPACITY         50
      END
    END

  END

