# #==================== BEGIN LIGGING PANDEN ===========================
# Ligging 'Onebekend'
  LAYER
    NAME                    "ligging_panden_onbekend"         # Lowercase naam in meervoud zonder afkortingen, zonder spaties en zonder leestekens (apostrofe)
    INCLUDE                 "connection/dataservices.inc"
    GROUP                   "panden_naar_ligging"                                 # Minstens 1 zelfde naam als de mapfile, of meerdere (slugified)
    DATA                    "geometrie FROM (
            SELECT id, geometrie, ligging_omschrijving FROM
                public.bag_panden_v1
            WHERE
                begin_geldigheid < now()
                AND (eind_geldigheid IS NULL OR eind_geldigheid > now())
                AND ligging_omschrijving IS NULL
                ) AS subquery
        USING srid=28992 USING UNIQUE id"

    TYPE                    POLYGON
    TEMPLATE                "empty"
    PROJECTION
      "init=epsg:28992"
    END

    METADATA
      "ows_title"           "Panden naar ligging: Onbekend" # Sentence case naam in meervoud met eventuele afkorting in haakjes erachter
      "ows_abstract"        "Panden naar ligging: Ligging Onbekend" # Door datateam aanleveren
      "wms_group_title"     "Panden naar ligging"                                 # Sentence case naam in meervoud met eventuele afkorting in haakjes erachter
      "gml_featureid"       "id"                                         # Unique ID volgens het Amsterdam Schema
      "gml_geometries"      "geometrie"
      "gml_geometry_type"   "multipolygon"                                      # Gelijk aan de TYPE van de LAYER
      "gml_include_items"   "all"                                        # Toon alle attributen in het GML antwoord (WMS én WFS)
      "gml_types"           "auto"
      "wms_include_items"   "all"                                        # Toon alle attributen in het CSV antwoord (WMS)
    END

    CLASS
      NAME                  "onbekend"           # Lowercase naam in enkelvoud zonder afkortingen, zonder spaties en zonder leestekens (apostrofe)
      TITLE                 "Onbekend"    # Sentence case naam in enkelvoud met eventuele afkorting in haakjes erachter
      STYLE
